Code.Terraform:
```hcl
# 确保 WAF Classic Global 规则至少具有一个条件
resource "aws_waf_rule" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "<example_metric_name>"

  # 关键：至少添加一个谓词（条件），以使该规则不为空
  predicate {
    data_id = "<example_resource_id>"  # 现有 IPSet ID
    negated = false
    type    = "IPMatch"
  }
}
```
